{"command": "python3 -c "
import csv, os, numpy as np, re
from pathlib import Path
from scipy.optimize import least_squares

root = Path('/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited')

def parse_param(col):
    for pat, scale in [(r'(\d+(?:\.\d+)?)\s*uM', 1.0), (r'(\d+(?:\.\d+)?)\s*mM', 1000.0),
                       (r'(\d+(?:\.\d+)?)\s*mg/mL', 1.0), (r'(\d+(?:\.\d+)?)\s*ng/ul', 1.0),
                       (r'pH\s+(\d+(?:\.\d+)?)', 1.0), (r'(\d+(?:\.\d+)?)\s*%', 1.0),
                       (r':\s*(\d+(?:\.\d+)?)\s*$', 1.0)]:
        m = re.search(pat, col, re.IGNORECASE)
        if m: return float(m.group(1)) * scale
    return None

def load_ds(p):
    with open(p) as f:
        reader = csv.reader(f, delimiter='\t')
        header = next(reader)
        rows = [[float(v) if v.strip() and v.strip().lower()!='nan' else float('nan') for v in r] for r in reader if r]
    arr = np.array(rows)
    t = arr[:,0]; y_cols = arr[:,1:]
    resp_hdrs = header[1:]
    parsed = [parse_param(h) for h in resp_hdrs]
    params = [float(p) for p in parsed] if all(p is not None for p in parsed) else [float(i+1) for i in range(len(resp_hdrs))]
    X, y = [], []
    for i, param in enumerate(params):
        for j in range(len(t)):
            val = y_cols[j, i]
            if np.isfinite(val):
                X.append([t[j], param]); y.append(val)
    return np.array(X), np.array(y)

# Test models
def stretched_exp(X, c):
    t, conc = X[:,0], X[:,1]
    tau = np.abs(c[2]) * np.abs(conc)**c[3]
    tau = np.maximum(tau, 1e-12)
    return c[4] * (1 - np.exp(-(t/tau)**np.abs(c[1]))) + c[5]

def meisl_logistic(X, c):
    t, conc = X[:,0], X[:,1]
    rate = np.abs(c[0]) * np.abs(conc)**c[1]
    t_half = np.abs(c[2]) * np.abs(conc)**c[3]
    return c[4] / (1 + np.exp(-rate * (t - t_half))) + c[5]

datasets = []
for dirpath, _, filenames in os.walk(root):
    if 'fit.tsv' in filenames:
        datasets.append(Path(dirpath) / 'fit.tsv')
datasets.sort()

results = {'stretched': [], 'meisl': []}
for p in datasets:
    try:
        X, y = load_ds(p)
        for name, fn, c0 in [
            ('stretched', stretched_exp, [2.0, 2.0, 5.0, -0.5, 1.0, 0.0]),
            ('meisl', meisl_logistic, [0.1, 0.5, 10.0, -0.5, 1.0, 0.0]),
        ]:
            def res(c, fn=fn, X=X, y=y):
                pred = fn(X, c)
                if not np.all(np.isfinite(pred)): return np.full(len(y), 1e6)
                return pred - y
            r = least_squares(res, c0, loss='soft_l1', max_nfev=500)
            pred = fn(X, r.x)
            nmse_v = np.mean((pred-y)**2)/np.var(y) if np.var(y)>0 else float('inf')
            results[name].append(nmse_v)
    except Exception as e:
        for name in results: results[name].append(float('inf'))

for name, vals in results.items():
    finite = [v for v in vals if np.isfinite(v)]
    print(f'{name}: mean_nmse={np.mean(finite):.4f}, n_finite={len(finite)}/{len(vals)}, median={np.median(finite):.4f}')
"
